if (! function_exists('university_info')) {
    function university_info($query, $timeout = null)
    {
        $query = trim($query ?? '');
        $timeout = (int)($timeout ?? 15);

        if (empty($query)) {
            return ['success' => false, 'error' => 'University name or country is required. Use "country=US" to search by country, or just a name to search globally.'];
        }

        // University hipolabs API — free, no key
        $url = 'http://universities.hipolabs.com/search?';
        if (stripos($query, 'country=') === 0) {
            // Search by country
            $url .= 'country=' . urlencode(substr($query, 8));
        } else {
            $url .= 'name=' . urlencode($query);
        }

        $context = stream_context_create([
            'http' => [
                'method' => 'GET',
                'timeout' => $timeout,
                'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: application/json\r\n",
                'ignore_errors' => true,
            ]
        ]);

        $response = @file_get_contents($url, false, $context);

        if ($response === false) {
            return ['success' => false, 'error' => 'Failed to reach university API.'];
        }

        $data = json_decode($response, true);

        if ($data === null) {
            return ['success' => false, 'error' => 'Failed to parse API response.'];
        }

        if (empty($data)) {
            return [
                'success' => true,
                'query' => $query,
                'results_count' => 0,
                'universities' => [],
                'message' => 'No universities found for: ' . $query,
            ];
        }

        // Process results
        $universities = [];
        $countries = [];
        $domains_seen = [];

        foreach ($data as $u) {
            $country = $u['country'] ?? '';
            $country_code = $u['alpha_two_code'] ?? '';
            $country_key = $country_code ?: $country;
            $countries[$country_key] = ($countries[$country_key] ?? 0) + 1;
            
            $domains = $u['domains'] ?? [];
            $web_pages = $u['web_pages'] ?? [];
            
            $universities[] = [
                'name' => $u['name'] ?? '',
                'country' => $country,
                'country_code' => $country_code,
                'domains' => $domains,
                'web_pages' => $web_pages,
                'state_province' => $u['state-province'] ?? null,
            ];
            
            foreach ($domains as $d) {
                $domains_seen[$d] = ($domains_seen[$d] ?? 0) + 1;
            }
        }

        // Sort by name
        usort($universities, fn($a, $b) => $a['name'] <=> $b['name']);

        return [
            'success' => true,
            'query' => $query,
            'results_count' => count($universities),
            'countries_found' => $countries,
            'unique_domains' => count($domains_seen),
            'universities' => $universities,
        ];
    }
